// ── Export chat as PDF ─────────────────────────────────────────────────────
function exportToPDF() {
  const rows = Array.from(chatArea.querySelectorAll('.message-row:not(.typing-row)'));
  if (rows.length === 0) {
    alert('Start a conversation first — there are no messages to export yet.');
    return;
  }

  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'letter' });

  const pageW    = doc.internal.pageSize.getWidth();
  const pageH    = doc.internal.pageSize.getHeight();
  const margin   = 20;
  const contentW = pageW - margin * 2;
  const footerY  = pageH - 12;
  let y = margin;

  function newPageIfNeeded(neededH) {
    if (y + neededH > footerY - 4) { doc.addPage(); y = margin; }
  }

  // Document header
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(15);
  doc.setTextColor(61, 139, 122);
  doc.text('Neurodiversity Support Coach', margin, y);
  y += 7;

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(9.5);
  doc.setTextColor(122, 118, 112);
  const dateStr = new Date().toLocaleDateString('en-US', {
    weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  });
  doc.text(dateStr, margin, y);
  y += 5;

  doc.setDrawColor(220, 218, 212);
  doc.line(margin, y, pageW - margin, y);
  y += 9;

  // Messages
  rows.forEach((row, idx) => {
    const isUser = row.classList.contains('user');
    const bubble = row.querySelector('.bubble');
    if (!bubble) return;
    const text = bubble.textContent.trim();
    if (!text) return;

    newPageIfNeeded(12);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(8);
    doc.setTextColor(isUser ? 61 : 100, isUser ? 139 : 95, isUser ? 122 : 90);
    doc.text(isUser ? 'YOU' : 'COACH', margin, y);
    y += 5;

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10.5);
    doc.setTextColor(42, 39, 34);
    const lines = doc.splitTextToSize(text, contentW);
    lines.forEach(line => {
      newPageIfNeeded(5.5);
      doc.text(line, margin, y);
      y += 5.5;
    });

    y += 5;

    if (idx < rows.length - 1 && y + 2 < footerY - 4) {
      doc.setDrawColor(238, 236, 231);
      doc.line(margin, y - 2, pageW - margin, y - 2);
    }
  });

  // Footer on every page
  const total = doc.internal.getNumberOfPages();
  for (let i = 1; i <= total; i++) {
    doc.setPage(i);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.setTextColor(180, 178, 173);
    doc.text('Neurodiversity Support Coach', margin, footerY);
    doc.text(i + ' / ' + total, pageW - margin, footerY, { align: 'right' });
  }

  doc.save('coach-session-' + new Date().toISOString().slice(0, 10) + '.pdf');
}

